import re
import json

data = locals()['var_function-call-180874714019438041']['results'][0]

def parse_location(description):
    match = re.search(r'in ([A-Za-z\s]+), ([A-Z]{2}),', description)
    if match:
        return match.group(2)
    return None

businesses = []
for record in data:
    business_id = record['business_id']
    description = record['description']
    state = parse_location(description)
    attributes = record.get('attributes')
    wifi = None
    if attributes and isinstance(attributes, dict):
        wifi = attributes.get('WiFi')
    elif attributes and isinstance(attributes, str):
        try:
            # Some attributes might be string representations of dictionaries
            attr_dict = json.loads(attributes.replace("'", '"'))
            wifi = attr_dict.get('WiFi')
        except json.JSONDecodeError:
            pass

    businesses.append({
        'business_id': business_id,
        'state': state,
        'wifi': wifi
    })

print("__RESULT__:")
print(json.dumps(businesses))

